riginalP[i])){int s=X.size();if(s+4>N)return 0;E(X,A,originalP[i]);A0(s);if((int)X.size()*100>S*C)return 0;}return (int)X.size()<S&&(int)X.size()*100<=S*C;}static int Sw(double r,double p,double ang,int R,double lim){AE q;q.AI=r*CL;q.BB=p*CL;q.BQ=cos(ang*acos(-1.)/180.);q.W=max(1e-11,1e-9*CL);q.AT=1.-1e-10;q.AJ=max(1e-30,1e-24*CL*CL);q.AA=0;int z=0;for(int it=0;it<R&&es()<lim;it++)for(int i=0;i<(int)faces.size()&&es()<lim;i++){if(!BR[i])continue;Face f=faces[i];int a=f.v[0],b=f.v[1],c=f.v[2];if(!BU[a]||!BU[b]||!BU[c])continue;double x=norm2(P[a]-P[b]),y=norm2(P[b]-P[c]),w=norm2(P[c]-P[a]);if(y<x&&y<w){if(GD(b,c,q))z++;}else if(w<x&&w<y){if(GD(c,a,q))z++;}else if(GD(a,b,q))z++;}return z;}struct T{double r,p,a,q,lim;int R,C,res;};static bool Try(const AP&B,int S,const T&t){rs(B);if(S<1200||es()>t.lim-.45)return 0;int before=cove();int z=Sw(t.r,t.p,t.a,t.R,t.lim-.85);if(z<max(16,before/400)){rs(B);return 0;}vector<Vec3>X;vector<Face>A;int v=Pk(X,A);if(v<64||v>=S){rs(B);return 0;}if(!Cv(X,A,S,t.C)){rs(B);return 0;}bool ok=0;if(AF(X,A)&&W5::strong_validator()&&cove()<S&&es()<t.lim){double s=vps(t.res);ok=s>=t.q;if(ok&&cove()<S*62/100&&es()<20.45&&t.res<192)ok=vps(192)>=t.q-.014;}if(!ok)rs(B);return ok;}static bool run(){if(N<25000||es()>19.35)return 0;int S=cove();if(S<2000||S>N)return 0;AP B=AD();T A[5];int n=0;if(N<120000){A[n++]={.080,.020,24.,.966,20.25,1,80,256};A[n++]={.125,.034,36.,.954,20.35,1,68,192};A[n++]={.190,.052,50.,.940,20.45,2,54,160};}else{A[n++]={.095,.024,26.,.962,20.15,1,78,128};A[n++]={.150,.040,40.,.948,20.30,1,64,112};A[n++]={.240,.070,58.,.932,20.45,2,48,96};A[n++]={.320,.090,70.,.920,20.55,2,38,80};}for(int i=0;i<n;i++)if(Try(B,S,A[i]))return 1;rs(B);return 0;}}'''

def die(msg):
    raise SystemExit("vxh_generator_abort: " + msg)

def blob_sha(data: bytes) -> str:
    return hashlib.sha1(b"blob " + str(len(data)).encode() + b"\0" + data).hexdigest()

def patch_source(src: str) -> str:
    for b in BAD:
        if b in src:
            die("stale VXH anchor present: " + b)
    for r in REQ:
        if r not in src:
            die("required anchor missing: " + r)
    old = next((m for m in MAIN_ANCHORS if src.count(m) == 1), None)
    if old is None:
        die("exact 81.93-family main anchor not found once")
    if "JD();return 0;}" in old:
        new = old.replace("if(N<50625&&es()<18.9)WK::run();JD();return 0;", "if(N<50625&&es()<18.9)WK::run();if(VXH::run()){JD();return 0;}JD();return 0;", 1)
    else:
        new = old.replace("if(N<50625&&es()<18.9)WK::run();JD();", "if(N<50625&&es()<18.9)WK::run();if(VXH::run()){JD();return 0;}JD();", 1)
    if new == old:
        die("main rewrite failed")
    anchor = "static void CA(string&out,const char*line,int len){"
    if src.count(anchor) != 1:
        die("CA output anchor not found once")
    src = src.replace(anchor, INS + anchor, 1)
    src = src.replace(old, new, 1)
    return src

TOKEN = re.compile(r'"(?:\\.|[^"\\])*"|\'(?:\\.|[^\'\\])*\'|(?<![A-Za-z0-9_])[A-Za-z_]\w*', re.S)
PROTECT = set('''alignas alignof and and_eq asm auto bitand bitor bool break case catch char char16_t char32_t class compl const constexpr const_cast continue decltype default delete do double dynamic_cast else enum explicit export extern false float for friend goto if inline int long mutable namespace new noexcept not not_eq nullptr operator or or_eq private protected public register reinterpret_cast return short signed sizeof static static_assert struct switch template this thread_local throw true try typedef typeid typename union unsigned using virtual void volatile wchar_t while xor xor_eq include define pragma main'''.split())
PROTECT |= set('''std algorithm array chrono utility cstdint queue cmath cstdio cstdlib cstring string vector unordered_map set map bitset iostream size_t uint64_t uint32_t int64_t int32_t FILE stdin stdout stderr sort min max swap fill unique adjacent_find lower_bound upper_bound find abs ceil floor sqrt cos sin acos atan2 fabs hypot pow isfinite strtod strtol fread fwrite printf fprintf snprintf setvbuf memset memcpy memmove reserve resize assign push_back insert erase end begin data clear empty size front back top pop push shrink_to_fit priority_queue less greater move pair make_pair tuple make_tuple steady_clock time_point duration count now _IOFBF'''.split())

def minify_identifiers(src: str) -> str:
    ids = []
    for m in TOKEN.finditer(src):
        s = m.group(0)
        if s and s[0] not in '"\'':
            ids.append(s)
    cnt = collections.Counter(ids)
    used = set(ids) | PROTECT
    alphabet = string.ascii_letters
    tail = string.ascii_letters + string.digits
    def names():
        for a in alphabet:
            yield a
        for a in alphabet:
            for b in tail:
                yield a + b
        for a in alphabet:
            for b in tail:
                for c in tail:
                    yield a + b + c
    cands = [x for x, c in cnt.items() if len(x) >= 3 and x not in PROTECT and not x.startswith('__')]
    cands.sort(key=lambda x: cnt[x] * (len(x) - 1), reverse=True)
    mp = {}
    gen = names()
    for x in cands:
        while True:
            y = next(gen)
            if y not in used and y not in PROTECT:
                break
        if len(y) < len(x):
            mp[x] = y
            used.add(y)
    def repl(m):
        s = m.group(0)
        if s and s[0] in '"\'':
            return s
        return mp.get(s, s)
    out = TOKEN.sub(repl, src)
    return out

def choose_input(arg):
    if arg:
        return Path(arg)
    for p in [Path("submission_580_81.93_7.cpp"), Path("fetched_sources/19901232.cpp"), Path("submission_543_81.93_7.cpp")]:
        if p.exists():
            return p
    die("missing base; pass submission_580_81.93_7.cpp or fetched_sources/19901232.cpp explicitly")

def compile_source(path: Path, static: bool):
    exe = path.with_suffix("")
    cmd = ["g++", "-std=c++17", "-O2", "-pipe"]
    if static:
        cmd += ["-static", "-s"]
    cmd += [str(path), "-o", str(exe)]
    subprocess.run(cmd, check=True)
    return exe, cmd

def run_sample(exe: Path, sample: Path):
    if not sample or not sample.exists():
        return None
    with sample.open("rb") as f:
        out = subprocess.check_output([str(exe)], stdin=f, timeout=10)
    return out.splitlines()[0].decode("ascii", "replace") if out else ""

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("src", nargs="?", default=None)
    ap.add_argument("-o", "--out", default="vxh_breakthrough.cpp")
    ap.add_argument("--allow-unknown-base", action="store_true")
    ap.add_argument("--no-minify", action="store_true")
    ap.add_argument("--no-compile", action="store_true")
    ap.add_argument("--no-static", action="store_true")
    ap.add_argument("--sample", default="sample.in")
    args = ap.parse_args()
    inp = choose_input(args.src)
    raw = inp.read_bytes()
    sh = blob_sha(raw)
    rel = str(inp).replace(os.sep, "/")
    if rel in KNOWN_BLOBS and sh != KNOWN_BLOBS[rel]:
        die(f"blob sha mismatch for {rel}: got {sh}, expected {KNOWN_BLOBS[rel]}")
    if rel not in KNOWN_BLOBS and not args.allow_unknown_base:
        die(f"unknown base path {rel}; pass --allow-unknown-base only after confirming anchors")
    src = raw.decode("utf-8")
    patched = patch_source(src)
    out = patched if args.no_minify else minify_identifiers(patched)
    if "VXH" in out and not args.no_minify:
        die("minifier failed to rename/integrate VXH; suspicious stale namespace")
    if "main" not in out:
        die("post-minify sanity check failed: main missing")
    n = len(out.encode("utf-8"))
    if n > LIMIT:
        die(f"generated source over limit: {n}>{LIMIT}")
    outp = Path(args.out)
    outp.write_text(out, encoding="utf-8", newline="")
    print(f"base={rel}")
    print(f"base_blob_sha={sh}")
    print(f"output={outp}")
    print(f"output_bytes={n}")
    print(f"source_limit={LIMIT}")
    print(f"delta_vs_base={n-len(raw):+d}")
    if not args.no_compile:
        if not shutil.which("g++"):
            die("g++ not found for mandatory self-check")
        exe, cmd = compile_source(outp, static=not args.no_static)
        print("compile=" + " ".join(cmd))
        first = run_sample(exe, Path(args.sample))
        if first is not None:
            print("sample_first_line=" + first)
            if first.strip() != "8 12":
                die("sample first line mismatch; expected 8 12")

if __name__ == "__main__":
    main()

