MAC = [
    ("O0", "double"), ("O1", "static"), ("O2", "const"), ("O3", "inline"),
    ("O4", "vector"), ("O5", "unsigned"), ("O6", "namespace"), ("O7", "struct"),
    ("O8", "template"), ("O9", "typename"), ("P0", "return false"),
    ("P1", "return true"), ("P2", "continue"), ("P3", "return"),
    ("P4", "int"), ("P5", "bool"), ("P6", "void"), ("P7", "class"),
]
ID = re.compile(r"[A-Za-z_][A-Za-z0-9_]*")
OPS3 = ("<<=", ">>=", "->*", "...")
OPS2 = ("++", "--", "->", "&&", "||", "<<", ">>", "<=", ">=", "==", "!=", "+=", "-=", "*=", "/=", "%=", "&=", "|=", "^=", "::", "##", ".*")
OPC = set("+-*&|<>=:*/.%^!#")

def die(msg):
    raise SystemExit("k3_guarded_generator_abort: " + msg)

def bsha(data: bytes) -> str:
    return hashlib.sha1(b"blob " + str(len(data)).encode() + b"\0" + data).hexdigest()

def scan(s: str):
    t = []
    i = 0
    n = len(s)
    bol = True
    while i < n:
        c = s[i]
        if c in " \t\r\n":
            if c == "\n":
                bol = True
            i += 1
            continue
        if bol and c == "#":
            j = s.find("\n", i)
            if j < 0:
                j = n
            t.append(("pp", s[i:j] + "\n"))
            i = j + 1
            bol = True
            continue
        bol = False
        if c == "/" and i + 1 < n and s[i + 1] == "/":
            j = s.find("\n", i + 2)
            if j < 0:
                break
            i = j + 1
            bol = True
            continue
        if c == "/" and i + 1 < n and s[i + 1] == "*":
            j = s.find("*/", i + 2)
            if j < 0:
                die("unterminated comment")
            i = j + 2
            continue
        if c in "\"'":
            q = c
            j = i + 1
            esc = False
            while j < n:
                ch = s[j]
                if esc:
                    esc = False
                elif ch == "\\":
                    esc = True
                elif ch == q:
                    j += 1
                    break
                j += 1
            t.append(("lit", s[i:j]))
            i = j
            continue
        m = ID.match(s, i)
        if m:
            t.append(("id", m.group(0)))
            i = m.end()
            continue
        if c.isdigit() or (c == "." and i + 1 < n and s[i + 1].isdigit()):
            j = i + 1
            while j < n and (s[j].isalnum() or s[j] in "._+-"):
                if s[j] in "+-" and not (j > i and s[j - 1] in "eEpP"):
                    break
                j += 1
            t.append(("num", s[i:j]))
            i = j
            continue
        z = s[i:i + 3]
        if z in OPS3:
            t.append(("op", z))
            i += 3
            continue
        z = s[i:i + 2]
        if z in OPS2:
            t.append(("op", z))
            i += 2
            continue
        t.append(("op", c))
        i += 1
    return t

def ids(s: str):
    return [v for k, v in scan(s) if k == "id"]

def need_space(a: str, b: str) -> bool:
    if not a or not b:
        return False
    x = a[-1]
    y = b[0]
    if (x.isalnum() or x == "_") and (y.isalnum() or y == "_"):
        return True
    if x == "." and y == ".":
        return True
    if x in OPC and y in OPC:
        return True
    return False

def transform(s: str) -> str:
    mp = {b: a for a, b in MAC if " " not in b}
    tok = scan(s)
    out = []
    prev = ""
    i = 0
    while i < len(tok):
        k, v = tok[i]
        if k == "pp":
            if out and out[-1] != "\n":
                out.append("\n")
            out.append(v)
            prev = "\n"
            i += 1
            continue
        if k == "id" and v == "return" and i + 1 < len(tok) and tok[i + 1][0] == "id" and tok[i + 1][1] in ("false", "true"):
            v = "P0" if tok[i + 1][1] == "false" else "P1"
            i += 1
        elif k == "id":
            v = mp.get(v, v)
        if need_space(prev, v):
            out.append(" ")
        out.append(v)
        prev = v
        i += 1
    return "".join(out)

def find_main(s: str):
    p = s.find("int main(){")
    if p < 0:
        die("missing int main(){ anchor")
    d = 0
    q = None
    esc = False
    start = s.find("{", p)
    for i in range(start, len(s)):
        c = s[i]
        if q:
            if esc:
                esc = False
            elif c == "\\":
                esc = True
            elif c == q:
                q = None
        else:
            if c in "\"'":
                q = c
            elif c == "{":
                d += 1
            elif c == "}":
                d -= 1
                if d == 0:
                    return p, i + 1
    die("unmatched main braces")

def choose_src(arg: str):
    if arg:
        return Path(arg), None
    for p, sh in CANDIDATE_BASES:
        pp = Path(p)
        if pp.exists():
            return pp, sh
    die("no 81.93-family base found; run from repo root or pass base source explicitly")

def patch_source(s: str) -> str:
    required = [
        "namespace W2G{", "namespace W2C{", "namespace W5{", "namespace VIMP{",
        "namespace MIDEC{", "namespace WK{", "static AP AD()", "static void rs(const AP&s)",
        "AF(", "W5::strong_validator", "vps(", "typedef double zz;",
        "static void CA(string&out,const char*line,int len){",
    ]
    for x in required:
        if x not in s:
            die("missing anchor: " + x)
    for x in ["namespace K3{", "K3::run()", "namespace VXH{", "VXH::run()"]:
        if x in s:
            die("forbidden stale anchor present: " + x)
    a, b = find_main(s)
    m = s[a:b]
    anchor = "MIDEC::run();WK::run();"
    if m.count(anchor) != 1:
        die("main insertion anchor not unique")
    m = m.replace(anchor, "MIDEC::run();if(K3::run()){JD();return 0;}WK::run();", 1)
    ca = "static void CA(string&out,const char*line,int len){"
    if s.count(ca) != 1:
        die("CA insertion anchor not unique")
    return s[:a] + LANE + m + s[b:].replace(ca, ca, 1)

def build_output(src: str) -> str:
    patched = patch_source(src)
    col = [x for x, _ in MAC if x in set(ids(patched))]
    if col:
        die("macro collision: " + ",".join(col))
    u = patched.find("using namespace std;")
    if u < 0:
        die("missing using namespace std")
    patched = patched[:u] + "".join("#define %s %s\n" % (a, b) for a, b in MAC) + patched[u:]
    out = transform(patched)
    if out.count("main(){") != 1:
        die("post-transform main anchor lost")
    if "K3::run()" not in out:
        die("post-transform K3 call lost")
    if "VXH::run()" in out or "namespace VXH" in out:
        die("forbidden VXH route present after transform")
    return out

def compile_and_sample(outp: Path, sample: Path, static: bool):
    if not shutil.which("g++"):
        die("g++ not found")
    exe = outp.with_suffix("")
    cmd = ["g++", "-std=c++17", "-O2", "-pipe"]
    if static:
        cmd += ["-static", "-s"]
    cmd += [str(outp), "-o", str(exe)]
    subprocess.run(cmd, check=True)
    print("compile=" + " ".join(cmd))
    if sample.exists():
        with sample.open("rb") as f:
            ans = subprocess.check_output([str(exe)], stdin=f, timeout=12)
        first = ans.splitlines()[0].decode("ascii", "replace") if ans else ""
        print("sample_first_line=" + first)
        if first.strip() != "8 12":
            die("sample first line mismatch; expected 8 12")
    else:
        print("sample_first_line=skipped_no_" + str(sample))

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("src", nargs="?", default=None)
    ap.add_argument("-o", "--out", default="k3_guarded_breakthrough.cpp")
    ap.add_argument("--allow-sha-mismatch", action="store_true")
    ap.add_argument("--no-compile", action="store_true")
    ap.add_argument("--no-static", action="store_true")
    ap.add_argument("--sample", default="sample.in")
    args = ap.parse_args()

    inp, expected_sha = choose_src(args.src)
    raw = inp.read_bytes()
    sh = bsha(raw)
    if expected_sha and sh != expected_sha and not args.allow_sha_mismatch:
        die("base blob sha mismatch got %s expected %s for %s" % (sh, expected_sha, inp))
    src = raw.decode("utf-8")
    out = build_output(src)
    n = len(out.encode("utf-8"))
    if n > LIMIT:
        die("generated source over limit: %d>%d" % (n, LIMIT))
    outp = Path(args.out)
    outp.write_text(out, encoding="utf-8", newline="")
    print("base=" + str(inp))
    print("base_blob_sha=" + sh)
    print("output=" + str(outp))
    print("output_bytes=%d" % n)
    print("source_limit=%d" % LIMIT)
    print("delta_vs_base=%+d" % (n - len(raw)))
    if not args.no_compile:
        compile_and_sample(outp, Path(args.sample), static=not args.no_static)

if __name__ == "__main__":
    main()

